import re
from collections import defaultdict

# Load the businesses data from the file
file_path = var_functions.query_db:48
with open(file_path, 'r') as f:
    businesses = json.load(f)

# Function to extract categories from description
def extract_categories(description):
    """Extract categories from description field."""
    if not description:
        return []

    categories = []
    desc_lower = description.lower()

    # Look for category patterns in description
    # Pattern 1: "services in X, Y, and Z."
    if 'services in' in desc_lower:
        start = desc_lower.find('services in') + len('services in')
        end = description.find('.', start)
        if end == -1:
            end = len(description)
        category_text = description[start:end].strip()
        # Split by comma and 'and'
        parts = re.split(r',|and', category_text)
        for part in parts:
            cat = part.strip().strip('.')
            if cat and len(cat) > 2:
                categories.append(cat)

    # Pattern 2: "fields of X, Y, and Z."
    elif 'fields of' in desc_lower:
        start = desc_lower.find('fields of') + len('fields of')
        end = description.find('.', start)
        if end == -1:
            end = len(description)
        category_text = description[start:end].strip()
        parts = re.split(r',|and', category_text)
        for part in parts:
            cat = part.strip().strip('.')
            if cat and len(cat) > 2:
                categories.append(cat)

    # Pattern 3: "including X, Y, and Z."
    elif 'including' in desc_lower:
        start = desc_lower.find('including') + len('including')
        end = description.find('.', start)
        if end == -1:
            end = len(description)
        category_text = description[start:end].strip()
        parts = re.split(r',|and', category_text)
        for part in parts:
            cat = part.strip().strip('.')
            if cat and len(cat) > 2:
                categories.append(cat)

    # Pattern 4: "category of 'X, Y'"
    elif "category of '" in description:
        match = re.search(r"category of '([^']+)'", description)
        if match:
            parts = re.split(r',', match.group(1))
            for part in parts:
                cat = part.strip()
                if cat and len(cat) > 2:
                    categories.append(cat)

    # Pattern 5: Simple list of categories at the end (fallback)
    if not categories:
        # Look for comma-separated items that look like categories
        words = description.split(',')
        if len(words) > 2:  # Likely a list
            for word in words:
                cat = word.strip().strip('.')
                if cat and len(cat) > 2 and not cat.startswith('Located at'):
                    # Check if it looks like a category (not address, not too long)
                    if len(cat) < 100 and ' at ' not in cat and ' in ' not in cat:
                        categories.append(cat)

    # Clean up categories
    cleaned_categories = []
    for cat in categories:
        cat = cat.strip()
        # Remove common prefixes
        if cat.startswith('and '):
            cat = cat[4:]
        if cat.startswith('in '):
            cat = cat[3:]
        cat = cat.strip()
        if cat and len(cat) > 2:
            cleaned_categories.append(cat)

    return cleaned_categories

# Process all businesses
category_counts = defaultdict(int)
business_categories = {}  # Maps numeric business_id to categories
business_ids = []  # List of numeric business IDs

for business in businesses:
    business_id = business.get('business_id', '')
    numeric_id = business_id.replace('businessid_', '')
    description = business.get('description', '')

    if numeric_id:
        business_ids.append(numeric_id)

    categories = extract_categories(description)

    if categories:
        business_categories[numeric_id] = categories
        for category in categories:
            category_counts[category] += 1

# Find the category with most businesses
sorted_categories = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)

if sorted_categories:
    top_category_name = sorted_categories[0][0]
    top_category_count = sorted_categories[0][1]
else:
    top_category_name = None
    top_category_count = 0

# Get business IDs for the top category
business_ids_in_top_category = []
for biz_id, categories in business_categories.items():
    if top_category_name in categories:
        business_ids_in_top_category.append(biz_id)

print('Top category:', top_category_name)
print('Number of businesses:', top_category_count)
print('Total businesses that accept credit cards:', len(businesses))
print('Sample business IDs in top category:', business_ids_in_top_category[:5])"}
